using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Tool state ---
var notes = new List<Note>();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// --- Build IChatClient ---
IChatClient chatClient = new ChatClientBuilder(
    new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation(options => options.MaximumIterationsPerRequest = 10)
    .Build();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWebAsync, "search_web",
        "Searches the web for information about a query. Returns text snippets from relevant sources."),
    AIFunctionFactory.Create(SaveNote, "save_note",
        "Saves a research note with a title and content for later reference."),
    AIFunctionFactory.Create(GetNotes, "get_notes",
        "Retrieves all previously saved research notes."),
};

// --- Create agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly by:
        1. Searching the web for relevant information using the search_web tool.
        2. Taking notes on key findings using the save_note tool.
        3. Searching for additional details or related subtopics as needed.
        4. When finished, retrieving your notes with get_notes and writing a comprehensive summary.

        Always save important findings as notes before providing your final summary.
        Make at least 2-3 different searches to gather diverse information.
        Structure your final summary with clear sections and cite your sources.
        """,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    tools: tools);

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n📚 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// --- Run agent ---
var response = await agent.RunAsync(
    $"Please research the following topic thoroughly: {topic}",
    options: new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    }));

Console.WriteLine(new string('─', 60));
Console.WriteLine("\n📋 RESEARCH SUMMARY\n");
Console.WriteLine(response.Text);

// --- Tool implementations ---

[Description("Searches the web for information about a query.")]
async Task<string> SearchWebAsync(
    [Description("The search query to look up")] string query,
    CancellationToken cancellationToken = default)
{
    Console.WriteLine($"  🔍 Searching: \"{query}\"");

    try
    {
        var encodedQuery = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetStringAsync(url, cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;
        var results = new List<string>();

        var abstractText = root.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrEmpty(abstractText))
        {
            var source = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            results.Add($"[Source: {source}] ({abstractUrl})\n{abstractText}");
        }

        if (root.TryGetProperty("RelatedTopics", out var relatedTopics))
        {
            foreach (var item in relatedTopics.EnumerateArray().Take(5))
            {
                if (item.TryGetProperty("Text", out var text)
                    && !string.IsNullOrEmpty(text.GetString()))
                {
                    var firstUrl = item.TryGetProperty("FirstURL", out var u)
                        ? u.GetString() : null;
                    results.Add(firstUrl is not null
                        ? $"({firstUrl})\n{text.GetString()}"
                        : text.GetString()!);
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n---\n\n", results)
            : $"No detailed results found for '{query}'. Try rephrasing or using different keywords.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

string SaveNote(
    [Description("A short descriptive title for the note")] string title,
    [Description("The detailed content of the note")] string content)
{
    Console.WriteLine($"  📝 Saving note: \"{title}\"");
    notes.Add(new Note(title, content, DateTime.UtcNow));
    return $"Note '{title}' saved successfully. Total notes: {notes.Count}.";
}

string GetNotes()
{
    Console.WriteLine("  📋 Retrieving all notes...");
    if (notes.Count == 0)
        return "No notes have been saved yet.";

    return string.Join("\n\n", notes.Select((n, i) =>
        $"── Note {i + 1}: {n.Title} ({n.SavedAt:u}) ──\n{n.Content}"));
}

