 [Description("Searches the web for information about a query.")]
 async Task<string> SearchWebAsync(
     [Description("The search query to look up")] string query,
     CancellationToken cancellationToken = default)
 {
     Console.WriteLine($"  🔍 Searching: \"{query}\"");

     try
     {
         var encodedQuery = Uri.EscapeDataString(query);
         var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";
         var json = await httpClient.GetStringAsync(url, cancellationToken);

         using var doc = JsonDocument.Parse(json);
         var root = doc.RootElement;
         var results = new List<string>();

         var abstractText = root.GetProperty("AbstractText").GetString();
         if (!string.IsNullOrEmpty(abstractText))
         {
             var source = root.GetProperty("AbstractSource").GetString();
             var abstractUrl = root.GetProperty("AbstractURL").GetString();
             results.Add($"[Source: {source}] ({abstractUrl})\n{abstractText}");
         }

         if (root.TryGetProperty("RelatedTopics", out var relatedTopics))
         {
             foreach (var item in relatedTopics.EnumerateArray().Take(5))
             {
                 if (item.TryGetProperty("Text", out var text)
                     && !string.IsNullOrEmpty(text.GetString()))
                 {
                     var firstUrl = item.TryGetProperty("FirstURL", out var u)
                         ? u.GetString() : null;
                     results.Add(firstUrl is not null
                         ? $"({firstUrl})\n{text.GetString()}"
                         : text.GetString()!);
                 }
             }
         }

         return results.Count > 0
             ? string.Join("\n\n---\n\n", results)
             : $"No detailed results found for '{query}'. Try rephrasing or using different keywords.";
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}. Try a different query.";
     }
 }

